2838994,-0.03839964,0.01085855,0.02575562,-0.03173102,0.00082660,0.08797161,0.09686168,-0.00725015,0.00629262,0.04440013,-0.04265946,0.06198188,-0.00723482,-0.01054750,-0.01589629,0.01432251,-0.04315927,-0.03392571,0.02983860,-0.03693259,0.04678478,0.02160211,-0.03608398,-0.02986240,-0.01280150,-0.05348713,-0.01412204,-0.02284046,0.03222724,0.01039041,-0.04260238,0.02443940,-0.01454249,0.06188671,0.01674189,-0.01921237,0.03675465,0.01880357,-0.04556279,0.12720567,-0.02486581,0.04124397]',E'Example Usage\n\n```go\npackage main\n\nimport (\n	"context"\n	"fmt"\n	"os"\n\n	"github.com/jackc/pgx/v5"\n)\n\nfunc main() {\n	// urlExample := "postgres://username:password@localhost:5432/database_name"\n	conn, err := pgx.Connect(context.Background(), os.Getenv("DATABASE_URL"))\n	if err != nil {\n		fmt.Fprintf(os.Stderr, "Unable to connect to database: %v\\n", err)\n		os.Exit(1)\n	}\n	defer conn.Close(context.Background())\n\n	var name string\n	var weight int64\n	err = conn.QueryRow(context.Background(), "select name, weight from widgets where id=$1", 42).Scan(&name, &weight)\n	if err != nil {\n		fmt.Fprintf(os.Stderr, "QueryRow failed: %v\\n", err)\n		os.Exit(1)\n	}\n\n	fmt.Println(name, weight)\n}\n```\n\nSee the [getting started guide](https://github.com/jackc/pgx/wiki/Getting-started-with-pgx) for more information.','{"source": "postgresql", "version": "17", "language": "go", "title": "pgx - PostgreSQL Driver and Toolkit", "section_title": "README", "url": "https://github.com/jackc/pgx/blob/master/README.md", "topics": "postgresql,pgx,go,sql,README", "categories": "database,sql,go"}');
